const data = $('Get Summary').first().json;
const signal = $('Get Signal').first().json;
const price = data.price?.current;
const dir = data.predictions?.['1h']?.direction || 'N/A';
const conf = data.predictions?.['1h']?.confidence || 0;
const emoji = dir === 'bullish' ? '🟢' : dir === 'bearish' ? '🔴' : '🟡';
const chartUrl = 'https://griffin-gold-production.up.railway.app/api/charts/prediction-card.png?timeframe=1h&size=default';

const embed = {
  embeds: [{
    title: `${emoji} Gold Prediction Update`,
    color: dir === 'bullish' ? 0x00ff00 : dir === 'bearish' ? 0xff0000 : 0xffff00,
    image: { url: chartUrl },
    fields: [
      { name: "💰 Price", value: `$${price?.toLocaleString() || 'N/A'}`, inline: true },
      { name: "📊 Direction", value: dir.toUpperCase(), inline: true },
      { name: "🎯 Confidence", value: `${Math.round(conf)}%`, inline: true },
      { name: "📈 1h Target", value: `$${data.predictions?.['1h']?.predicted_price?.toLocaleString() || 'N/A'}`, inline: true },
      { name: "📈 4h Target", value: `$${data.predictions?.['4h']?.predicted_price?.toLocaleString() || 'N/A'}`, inline: true },
      { name: "📈 24h Target", value: `$${data.predictions?.['24h']?.predicted_price?.toLocaleString() || 'N/A'}`, inline: true },
      { name: "✅ 7d Accuracy", value: `${data.accuracy_7d?.overall_pct || 'N/A'}%`, inline: true },
      { name: "🌡️ Sentiment", value: data.sentiment?.label?.toUpperCase() || 'N/A', inline: true },
      { name: "😱 Fear/Greed", value: `${data.macro?.fear_greed_index || 'N/A'} (${data.macro?.fear_greed_label || 'N/A'})`, inline: true }
    ],
    footer: { text: "Griffin Gold AI | Try @GriffinGoldBot on Telegram" },
    timestamp: new Date().toISOString()
  }]
};
return [{ json: { ...embed, chartUrl } }];

const now = new Date().toISOString();
const embed = $('Build Discord Embed').first().json;
const title = embed.embeds?.[0]?.title || 'Unknown';
console.log(`[${now}] Discord embed posted: ${title}`);
return [{ json: { status: 'posted', platform: 'discord', timestamp: now, embed_title: title } }];
